+    let mut pid: libc::pid_t = -1;
+
+    let rc = unsafe {
+        posix_spawnp(
+            &mut pid,
+            missing.as_ptr(),
+            std::ptr::null(),
+            std::ptr::null(),
+            argv.as_ptr().cast(),
+            envp.as_ptr().cast(),
